import { useEffect, useState } from "react";

export default function Dashboard() {
  const [data, setData] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/dashboard")
      .then(res => res.json())
      .then(setData);
  }, []);

  return (
    <div>
      <h2>Dashboard</h2>

      <table border="1">
        <tr>
          <th>Center</th>
          <th>Date</th>
          <th>Doses</th>
        </tr>

        {data.map((d, i) => (
          <tr key={i}>
            <td>{d.center_id}</td>
            <td>{d.date}</td>
            <td>{d.count}</td>
          </tr>
        ))}
      </table>
    </div>
  );
}
